(window.webpackJsonp=window.webpackJsonp||[]).push([[11],{224:function(t,e,c){"use strict";c.r(e);var o=c(0),d=Object(o.a)({},function(){this.$createElement;this._self._c;return this._m(0)},[function(){var t=this,e=t.$createElement,c=t._self._c||e;return c("div",{staticClass:"content"},[c("h2",{attrs:{id:"title-12-monkeysdate-2016-06-19-22-10-11categories-观影tags-moviethumbnail-http-7xopm5-com1-z0-glb-clouddn-com-2016-07-03-7b332404b39d255ef3ce20cbdc4dc01b-jpg"}},[c("a",{staticClass:"header-anchor",attrs:{href:"#title-12-monkeysdate-2016-06-19-22-10-11categories-观影tags-moviethumbnail-http-7xopm5-com1-z0-glb-clouddn-com-2016-07-03-7b332404b39d255ef3ce20cbdc4dc01b-jpg","aria-hidden":"true"}},[t._v("#")]),t._v(" title: 12 monkeys\ndate: 2016-06-19 22:10:11\ncategories: 观影\ntags: movie\nthumbnail: http://7xopm5.com1.z0.glb.clouddn.com/2016/07/03/7b332404b39d255ef3ce20cbdc4dc01b.jpg")]),t._v(" "),c("p",[c("img",{attrs:{src:"http://7xopm5.com1.z0.glb.clouddn.com/2016/07/03/7b332404b39d255ef3ce20cbdc4dc01b.jpg",alt:""}})]),t._v(" "),c("blockquote",[c("p",[t._v("温馨提示：以下内容严重剧透")])]),t._v(" "),c("p",[t._v("这部电影让我找回了看电影的乐趣。")]),t._v(" "),c("p",[t._v("之前小伙伴向我推荐过这部电影，因为译名太普通所以并没有放在心上。最近在找黑客题材电影时恰好又看到这部电影 ，既然这么有缘那就看吧。一同找到的还有另外一部 —— 《The 13th Floor》（异次元骇客），而后者的中文译名相对而言更有黑客范一点，所以先看的后者。")]),t._v(" "),c("p",[t._v("说到中文译名，有时候简直是无力吐槽，明显的哗众取宠。当你发现看完整部电影，你会发现剧情和译名没有半毛钱关系。还有些译名更可恶，简直是剧透了整部电影。没有了悬念的电影还有什么看点,所以我看电影前一般都不会看简介。")]),t._v(" "),c("p",[t._v("这部电影的讲的是 96 年世界各地区相继爆发了大规模的病毒感染，50 亿人被夺走生命（96 年年中世界人口约为 57.5 亿），地面不再安全，人们只能生活在与地面隔离的地底（为什么地面的动物没事？）。这里挺有趣的，这部电影是在 95 年 12 月 27 日上映的，拍摄时间应该也是在 95 年，一般电影描述的大灾难都是在未来很多年后才爆发，而这部电影的爆发时间却是在即将到来的 9 6 年。或许是为了达到更好的观影效果，让观众保持神经的紧绷吧，2012 年的时候不是也有很多人在倒计时么，也可能仅仅是剧情需要而已。")]),t._v(" "),c("p",[t._v("住在地底的人们无时无刻都在想怎么回到地面，终于在多年后科学家们掌握了穿越时空的技术，他们派出自愿（被自愿）的囚徒回到 96 年找病毒样本（只是收集病毒样本，不是阻止病毒爆发），并承诺给他们减刑。派出的前几个“自愿者”因为意志不够坚定没能完成任务，所以他们在 2036 年的时候，选中了意志坚定的詹姆斯·科尔（詹姆斯·威利斯饰）。如何得知是在 2036 年？荷西在 96 年这么说过：")]),t._v(" "),c("p",[c("img",{attrs:{src:"http://7xopm5.com1.z0.glb.clouddn.com/2016/07/03/2dd4cc0bbb55f4a843b9f2cd74b7736e.JPG",alt:"117:15",title:"117:15"}})]),t._v(" "),c("blockquote",[c("p",[t._v("这里比较奇怪，既然不是去阻止病毒爆发，仅仅只是去收集病毒样本，为什么还要回到过去收集，现在的地面上不是有很多吗？詹姆斯·科尔开始在地面收集的蟑螂和蜘蛛是用来干什么的？难道只是为了测试他意志够不够坚强吗？")])]),t._v(" "),c("p",[t._v("因为穿越时空的技术还不是很成熟，詹姆斯被送到了错误的年代（90 年）。90 年的人们根本不相信他说的一切，又因为他意志太坚强了，暴力起来表现的活像一个神经病，以至于被当成神经病关进了精神病院。")]),t._v(" "),c("blockquote",[c("p",[t._v("说实话，一开始我也认为他是神经病，这一切只是他的幻想。2036 年的技术真的有这么渣么（下图），这样的技术也可以玩穿越吗，我表示很怀疑啊...")])]),t._v(" "),c("p",[c("img",{attrs:{src:"http://7xopm5.com1.z0.glb.clouddn.com/2016/07/03/7286ee6d605770fa01edc0eb27817481.JPG",alt:"09:15",title:"09:15"}})]),t._v(" "),c("p",[t._v("在里面他认识了真正的精神病患者杰弗里·戈因斯（布拉德·皮特饰）。")]),t._v(" "),c("blockquote",[c("p",[t._v("这家伙我一眼就认出他了，也终于知道为什么小伙伴会向我推荐这部电影了，因为他是布拉德·皮特的影迷。")])]),t._v(" "),c("p",[t._v("过去不可改变\n类恐怖游轮，逻辑问题，詹姆斯没理由回去。\nhttps://movie.douban.com/review/2759072/")])])}],!1,null,null,null);e.default=d.exports}}]);